SELECT setval('user_reactions_id_seq', 101, true); -- Setting high after user IDs
SELECT setval('reports_id_seq', 101, true); -- Setting high after user IDs
SELECT setval('category_follows_id_seq', 501, true); -- Setting high after manual follows inserts
SELECT setval('category_moderators_id_seq', 201, true); -- Setting high after manual moderators inserts
SELECT setval('avatars_id_seq', 101, true); -- Setting high after avatar inserts
SELECT setval('posts_id_seq', 16, true); -- Original script inserted posts up to ID 15

