INSERT INTO posts (title, body, comments_count, type, created_at, updated_at, user_id, category_id) VALUES
                                                                                                        ('Just got my new RTX 4090!', 'Wow, the performance jump is insane! Been playing Cyberpunk 2077 maxed out. Anyone else upgrade recently? What games are you testing first? Share your benchmarks!', 0, 'DISCUSSION', NOW() - (random() * 300 * INTERVAL '1 day'), NOW() - (random() * 24 * INTERVAL '1 hour'), 1, 2), -- Technology user, Gaming category
                                                                                                        ('Seeking advice on learning SQL joins', 'I''m struggling with complex joins, especially LEFT vs INNER. Can someone explain with a simple example or point to a good tutorial?', 0, 'QUESTION', NOW() - (random() * 300 * INTERVAL '1 day'), NOW() - (random() * 24 * INTERVAL '1 hour'), 4, 4), -- Programming user, Programming category
                                                                                                        ('Showcasing my latest abstract painting', 'Happy to share my recent work! It''s called "Entropy". Would love to hear your interpretations or feedback. What does it make you feel?', 0, 'DISCUSSION', NOW() - (random() * 300 * INTERVAL '1 day'), NOW() - (random() * 24 * INTERVAL '1 hour'), 5, 5), -- Art user, Art category
                                                                                                        ('Underrated artists you love?', 'Looking for some hidden gems in the music world. Any genre welcome! Share your favorite lesser-known musicians or bands.', 0, 'DISCUSSION', NOW() - (random() * 300 * INTERVAL '1 day'), NOW() - (random() * 24 * INTERVAL '1 hour'), 6, 6), -- Music user, Music category
                                                                                                        ('What are your favorite comfort food recipes?', 'Rainy day here and I''m craving something warm and cozy. Share your go-to comfort food recipes! Bonus points for easy ones.', 0, 'DISCUSSION', NOW() - (random() * 300 * INTERVAL '1 day'), NOW() - (random() * 24 * INTERVAL '1 hour'), 9, 9), -- Food & Cooking user, Food & Cooking category
                                                                                                        ('Tips for solo travel in Southeast Asia', 'Planning a backpacking trip for a month next year. Any advice on destinations, budget, or safety tips for solo female travelers?', 0, 'QUESTION', NOW() - (random() * 300 * INTERVAL '1 day'), NOW() - (random() * 24 * INTERVAL '1 hour'), 10, 10), -- Travel user, Travel category
                                                                                                        ('Discussion: The future of renewable energy', 'Heard about a breakthrough in solar panel efficiency. What are your thoughts on the most promising renewable energy technologies?', 0, 'DISCUSSION', NOW() - (random() * 300 * INTERVAL '1 day'), NOW() - (random() * 24 * INTERVAL '1 hour'), 1, 3), -- Technology user, Science category
                                                                                                        ('Reviewing the new action RPG, "Eldoria"', 'Just finished the main story of Eldoria. Overall a solid 8/10 for me. The combat is fluid, but the story felt a bit rushed. What did you guys think?', 0, 'DISCUSSION', NOW() - (random() * 300 * INTERVAL '1 day'), NOW() - (random() * 24 * INTERVAL '1 hour'), 2, 2), -- Gaming user, Gaming category
                                                                                                        ('Anyone else excited for the [Upcoming Movie]? Trailer reaction!', 'Just saw the new trailer and I''m hyped! The visuals look stunning. What are your expectations? Avoiding spoilers!', 0, 'DISCUSSION', NOW() - (random() * 300 * INTERVAL '1 day'), NOW() - (random() * 24 * INTERVAL '1 hour'), 7, 7), -- Movies & TV user, Movies & TV category
                                                                                                        ('Seeking recommendations for epic fantasy series', 'Finished Sanderson''s Stormlight Archive and need something new to sink my teeth into. Looking for sprawling worlds and deep lore.', 0, 'QUESTION', NOW() - (random() * 300 * INTERVAL '1 day'), NOW() - (random() * 24 * INTERVAL '1 hour'), 8, 8), -- Books user, Books category
                                                                                                        ('Training for my first marathon - wish me luck!', 'Starting my training plan this week. Feeling excited and nervous! Any veteran marathoners have essential tips or motivation?', 0, 'DISCUSSION', NOW() - (random() * 300 * INTERVAL '1 day'), NOW() - (random() * 24 * INTERVAL '1 hour'), 11, 11), -- Sports user, Sports category
                                                                                                        ('Effective mindfulness techniques for stress', 'Finding it hard to unwind lately. What mindfulness or meditation techniques do you use to manage stress?', 0, 'QUESTION', NOW() - (random() * 300 * INTERVAL '1 day'), NOW() - (random() * 24 * INTERVAL '1 hour'), 12, 12), -- Health & Fitness user, Health & Fitness category
                                                                                                        ('Latest developments in JavaScript frameworks - Svelte 5?', 'Been playing around with the new Svelte 5 runestones. Feels promising! How are other frameworks like React and Vue evolving?', 0, 'DISCUSSION', NOW() - (random() * 300 * INTERVAL '1 day'), NOW() - (random() * 24 * INTERVAL '1 hour'), 4, 4), -- Programming user, Programming category
                                                                                                        ('Best indie games released this year?', 'So many amazing indie titles come out every month. Which ones have really captured your attention lately?', 0, 'DISCUSSION', NOW() - (random() * 300 * INTERVAL '1 day'), NOW() - (random() * 24 * INTERVAL '1 hour'), 2, 2), -- Gaming user, Gaming category
                                                                                                        ('The ethics of gene editing technology', 'A complex and important topic. What are the main ethical considerations we need to think about as gene editing becomes more accessible?', 0, 'DISCUSSION', NOW() - (random() * 300 * INTERVAL '1 day'), NOW() - (random() * 24 * INTERVAL '1 hour'), 3, 3), -- Science category (random user)
                                                                                                        ('Simple vs Complex App Architecture', 'Discussing the trade-offs between building simple, monolithic applications and more complex, microservice-based ones. When is each appropriate?', 0, 'DISCUSSION', NOW() - (random() * 300 * INTERVAL '1 day'), NOW() - (random() * 24 * INTERVAL '1 hour'), floor(random() * 100) + 1, 4), -- Programming category (random user)
                                                                                                        ('Tips for capturing great portrait photos', 'Struggling with lighting and composition in my portrait photography. Any pro tips for getting those stunning shots?', 0, 'QUESTION', NOW() - (random() * 300 * INTERVAL '1 day'), NOW() - (random() * 24 * INTERVAL '1 hour'), floor(random() * 100) + 1, 5), -- Art category (random user)
                                                                                                        ('What music are you listening to while coding/working?', 'Need some background music that helps concentration but isn''t distracting. Share your favorite playlists or artists for work!', 0, 'DISCUSSION', NOW() - (random() * 300 * INTERVAL '1 day'), NOW() - (random() * 24 * INTERVAL '1 hour'), floor(random() * 100) + 1, 6), -- Music category (random user)
                                                                                                        ('Favorite movie moments that gave you chills?', 'You know, those scenes that are just perfect - whether it''s acting, visuals, or music. Which movie moments stick with you?', 0, 'DISCUSSION', NOW() - (random() * 300 * INTERVAL '1 day'), NOW() - (random() * 24 * INTERVAL '1 hour'), floor(random() * 100) + 1, 7), -- Movies & TV category (random user)
                                                                                                        ('Underrated classic novels?', 'Beyond the usual suspects like Austen or Dickens, what older books do you think deserve more love and attention?', 0, 'DISCUSSION', NOW() - (random() * 300 * INTERVAL '1 day'), NOW() - (random() * 24 * INTERVAL '1 hour'), floor(random() * 100) + 1, 8), -- Books category (random user)
                                                                                                        ('My journey trying to bake sourdough bread', 'It''s been a challenging but rewarding process! Share your sourdough wins or fails, and maybe some starter tips?', 0, 'DISCUSSION', NOW() - (random() * 300 * INTERVAL '1 day'), NOW() - (random() * 24 * INTERVAL '1 hour'), floor(random() * 100) + 1, 9), -- Food & Cooking category (random user)
                                                                                                        ('Packing hacks for minimalists?', 'Trying to travel lighter. What are your best tips for packing everything you need into a small carry-on?', 0, 'QUESTION', NOW() - (random() * 300 * INTERVAL '1 day'), NOW() - (random() * 24 * INTERVAL '1 hour'), floor(random() * 100) + 1, 10), -- Travel category (random user)
                                                                                                        ('How to stay motivated for workouts?', 'Struggling to stick to a consistent exercise routine. What are your secrets for staying motivated long-term?', 0, 'QUESTION', NOW() - (random() * 300 * INTERVAL '1 day'), NOW() - (random() * 24 * INTERVAL '1 hour'), floor(random() * 100) + 1, 12), -- Health & Fitness category (random user)
                                                                                                        ('Benefits of intermittent fasting?', 'Considering trying intermittent fasting for health reasons. What are the scientifically-backed benefits and potential downsides?', 0, 'DISCUSSION', NOW() - (random() * 300 * INTERVAL '1 day'), NOW() - (random() * 24 * INTERVAL '1 hour'), floor(random() * 100) + 1, 12), -- Health & Fitness category (random user)
                                                                                                        ('Is now a good time to build a new PC?', 'With component prices fluctuating, is it a good idea to build a gaming/workstation PC now or wait?', 0, 'QUESTION', NOW() - (random() * 300 * INTERVAL '1 day'), NOW() - (random() * 24 * INTERVAL '1 hour'), floor(random() * 100) + 1, floor(random() * 2) + 1), -- Tech or Gaming category (random user)
                                                                                                        ('Any cool mobile games you recommend?', 'Looking for something fun to play on my phone during commutes. Gacha, puzzle, RPG - open to anything!', 0, 'QUESTION', NOW() - (random() * 300 * INTERVAL '1 day'), NOW() - (random() * 24 * INTERVAL '1 hour'), floor(random() * 100) + 1, 2), -- Gaming category (random user)
                                                                                                        ('Understanding dark matter and dark energy', 'Still wrap my head around these concepts. Can someone explain them in simpler terms?', 0, 'QUESTION', NOW() - (random() * 300 * INTERVAL '1 day'), NOW() - (random() * 24 * INTERVAL '1 hour'), floor(random() * 100) + 1, 3), -- Science category (random user)
                                                                                                        ('Learning Rust - steep learning curve?', 'Just started diving into Rust and wow, the borrow checker is a challenge! Anyone have tips for new Rustaceans?', 0, 'DISCUSSION', NOW() - (random() * 300 * INTERVAL '1 day'), NOW() - (random() * 24 * INTERVAL '1 hour'), floor(random() * 100) + 1, 4), -- Programming category (random user)
                                                                                                        ('Share your favorite digital art tools/software', 'Whether it''s Photoshop, Procreate, Krita, or something else, what are your go-to programs for digital art creation?', 0, 'DISCUSSION', NOW() - (random() * 300 * INTERVAL '1 day'), NOW() - (random() * 24 * INTERVAL '1 hour'), floor(random() * 100) + 1, 5), -- Art category (random user)
                                                                                                        ('Best albums to listen to on vinyl?', 'Just got a record player! What albums have a distinctly better listening experience on vinyl?', 0, 'DISCUSSION', NOW() - (random() * 300 * INTERVAL '1 day'), NOW() - (random() * 24 * INTERVAL '1 hour'), floor(random() * 100) + 1, 6), -- Music category (random user)
